     6→const SubscriptionContext = createContext(null);
     7→
     8→export function useSubscription() {
     9→  return useContext(SubscriptionContext);
    10→}
    11→
    12→const PLANS = {
    13→  free: {
    14→    name: 'Free',
    15→    dailyLimit: 5,
    16→    categories: ['marketing', 'content'],
    17→  },
    18→  pro: {
    19→    name: 'Pro',
    20→    dailyLimit: Infinity,
    21→    categories: ['marketing', 'content', 'strategy', 'digital', 'ecommerce', 'agency', 'startup'],
    22→  },
    23→  business: {
    24→    name: 'Business',
    25→    dailyLimit: Infinity,
    26→    categories: ['marketing', 'content', 'strategy', 'digital', 'ecommerce', 'agency', 'startup'],
    27→  },
    28→  admin: {
    29→    name: 'Admin',
    30→    dailyLimit: Infinity,
    31→    categories: ['marketing', 'content', 'strategy', 'digital', 'ecommerce', 'agency', 'startup', 'automation'],
    32→  },
    33→};
    34→
    35→export function SubscriptionProvider({ children }) {
    36→  const { currentUser, userProfile, refreshUserProfile } = useAuth();
    37→  const [subscription, setSubscription] = useState('free');
    38→  const [usageCount, setUsageCount] = useState(0);
    39→  const [checkingSubscription, setCheckingSubscription] = useState(true);
    40→
    41→  useEffect(() => {
    42→    if (userProfile) {
    43→      setSubscription(userProfile.subscription || 'free');
    44→      setUsageCount(userProfile.usageCount || 0);
    45→      setCheckingSubscription(false);
    46→    } else {
    47→      setCheckingSubscription(false);
    48→    }
    49→  }, [userProfile]);
    50→
    51→  function canUseTool(categoryId) {
    52→    if (!currentUser) return false;
    53→    if (subscription === 'admin') return true;
    54→    const plan = PLANS[subscription] || PLANS.free;
    55→    if (!plan.categories.includes(categoryId)) return false;
    56→    if (plan.dailyLimit !== Infinity && usageCount >= plan.dailyLimit) return false;
    57→    return true;
    58→  }
    59→
    60→  function isCategoryLocked(categoryId) {
    61→    if (subscription === 'admin') return false;
    62→    const plan = PLANS[subscription] || PLANS.free;
    63→    return !plan.categories.includes(categoryId);
    64→  }
    65→
    66→  async function trackUsage() {
    67→    if (!currentUser) return;
    68→    try {
    69→      const userRef = doc(db, 'users', currentUser.uid);
    70→      await updateDoc(userRef, { usageCount: increment(1) });
    71→      setUsageCount((prev) => prev + 1);
    72→    } catch (err) {
    73→      console.error('Error tracking usage:', err);
    74→    }
    75→  }
    76→
    77→  function getPlanLimits() {
    78→    return PLANS[subscription] || PLANS.free;
    79→  }
    80→
    81→  function isAtLimit() {
    82→    if (subscription === 'admin') return false;
    83→    const plan = PLANS[subscription] || PLANS.free;
    84→    return plan.dailyLimit !== Infinity && usageCount >= plan.dailyLimit;
    85→  }
    86→
    87→  const value = {
    88→    subscription,
    89→    usageCount,
    90→    checkingSubscription,
    91→    canUseTool,
    92→    isCategoryLocked,
    93→    trackUsage,
    94→    getPlanLimits,
    95→    isAtLimit,
    96→    PLANS,
    97→    refreshUserProfile,
    98→  };
    99→
   100→  return (
   101→    <SubscriptionContext.Provider value={value}>
   102→      {children}
   103→    </SubscriptionContext.Provider>
   104→  );
   105→}
