    65→export default function AIToolInterface({ tool, categoryId }) {
    66→  const [inputs, setInputs] = useState({});
    67→  const [output, setOutput] = useState('');
    68→  const [isStreaming, setIsStreaming] = useState(false);
    69→  const [error, setError] = useState('');
    70→  const [copied, setCopied] = useState(false);
    71→  const [wordCount, setWordCount] = useState(0);
    72→  const outputRef = useRef(null);
    73→  const abortRef = useRef(false);
    74→
    75→  const { currentUser } = useAuth();
    76→  const { canUseTool, trackUsage, isAtLimit, subscription } = useSubscription();
    77→  const { t, i18n } = useTranslation();
    78→
    79→  // Reset when tool changes
    80→  useEffect(() => {
    81→    setInputs({});
    82→    setOutput('');
    83→    setError('');
    84→    setIsStreaming(false);
    85→  }, [tool?.id]);
    86→
    87→  // Track word count
    88→  useEffect(() => {
    89→    if (output) {
    90→      setWordCount(output.split(/\s+/).filter(Boolean).length);
    91→    } else {
    92→      setWordCount(0);
    93→    }
    94→  }, [output]);
    95→
    96→  // Auto-scroll output
    97→  useEffect(() => {
    98→    if (outputRef.current && isStreaming) {
    99→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
   100→    }
   101→  }, [output, isStreaming]);
   102→
   103→  function handleInputChange(fieldId, value) {
   104→    setInputs((prev) => ({ ...prev, [fieldId]: value }));
   105→  }
   106→
   107→  function validateInputs() {
   108→    const required = tool.inputs.filter((f) => f.required);
   109→    for (const field of required) {
   110→      if (!inputs[field.id] || inputs[field.id].trim() === '') {
   111→        const fieldLabel = t(`input.${tool.id}.${field.id}.label`, { defaultValue: field.label });
   112→        return `"${fieldLabel}" is required`;
   113→      }
   114→    }
   115→    return null;
   116→  }
   117→
   118→  async function handleGenerate(e) {
   119→    e.preventDefault();
   120→    setError('');
   121→
   122→    if (!currentUser) {
   123→      setError('Please sign in to use this tool.');
   124→      return;
   125→    }
   126→
   127→    if (!canUseTool(categoryId)) {
   128→      if (isAtLimit()) {
   129→        setError(t('ui.dailyLimitText', { limit: 5, defaultValue: "Daily usage limit reached. Upgrade to Pro for unlimited access." }));
   130→      } else {
   131→        setError(t('ui.proOnlyText', { defaultValue: 'This category is available on Pro and Business plans.' }));
   132→      }
   133→      return;
   134→    }
   135→
   136→    const validationError = validateInputs();
   137→    if (validationError) {
   138→      setError(validationError);
   139→      return;
   140→    }
   141→
   142→    setOutput('');
   143→    setIsStreaming(true);
   144→    abortRef.current = false;
   145→
   146→    await streamAIResponse({
   147→      categoryId,
   148→      toolId: tool.id,
   149→      inputs: { ...inputs, _language: i18n.language },
   150→      onChunk: (text) => {
   151→        if (!abortRef.current) {
   152→          setOutput((prev) => prev + text);
   153→        }
   154→      },
   155→      onDone: () => {
   156→        setIsStreaming(false);
   157→        trackUsage();
   158→      },
   159→      onError: (msg) => {
   160→        setIsStreaming(false);
   161→        setError(msg);
   162→      },
   163→    });
   164→  }
   165→
